  assigns jsonb := $json$ [{"p": "SKN-SICK", "t": "TPL-STB-SICKNESS"}, {"p": "SKN-MAT", "t": "TPL-STB-MATERNITY"}, {"p": "SKN-EI-INJ", "t": "TPL-EI-INJURY"}, {"p": "SKN-EI-DIS", "t": "TPL-EI-DISABLEMENT"}, {"p": "SKN-EI-MED", "t": "TPL-EI-MEDICAL-EXPENSE"}, {"p": "SKN-EI-DTH", "t": "TPL-EI-DEATH"}, {"p": "SKN-FUN", "t": "TPL-GRANT-FUNERAL"}, {"p": "SKN-INV", "t": "TPL-LTB-INVALIDITY"}, {"p": "SKN-AGE", "t": "TPL-LTB-AGE"}, {"p": "SKN-SUR", "t": "TPL-LTB-SURVIVORS"}, {"p": "SKN-NCP", "t": "TPL-NCP-ASSISTANCE"}, {"p": "SKN-SVC-LIFE", "t": "TPL-SVC-LIFE-CERT"}, {"p": "SKN-SVC-SCH", "t": "TPL-SVC-SCHOOL-CERT"}, {"p": "SKN-SVC-EFT", "t": "TPL-SVC-EFT-UPDATE"}, {"p": "SKN-SVC-EIR", "t": "TPL-SVC-EMPLOYER-INFO"}] $json$::jsonb;
  sections jsonb;
  tpl jsonb;
  fld jsonb;
  asn jsonb;
  tpl_id uuid;
BEGIN
  sections := payload->'sections';

  FOR tpl IN SELECT * FROM jsonb_array_elements(payload->'templates') LOOP
    INSERT INTO public.bn_screen_template
      (template_code, template_name, description, sections, layout_type, country_code, is_active, entered_by)
    VALUES (tpl->>'code', tpl->>'name', tpl->>'desc', sections, 'TABBED', 'SKN', TRUE, 'SEED')
    ON CONFLICT (template_code) DO NOTHING;

    SELECT id INTO tpl_id FROM public.bn_screen_template WHERE template_code = tpl->>'code';

    FOR fld IN SELECT * FROM jsonb_array_elements(tpl->'fields') LOOP
      INSERT INTO public.bn_field_metadata
        (screen_template_id, field_code, field_label, field_type, section_code, is_required, validation_rules, sort_order, is_active, entered_by)
      SELECT tpl_id, fld->>'c', fld->>'l', fld->>'t', fld->>'s', (fld->>'r')::boolean, fld->'v', (fld->>'o')::int, TRUE, 'SEED'
      WHERE NOT EXISTS (
        SELECT 1 FROM public.bn_field_metadata f
        WHERE f.screen_template_id = tpl_id AND f.field_code = fld->>'c'
      );
    END LOOP;

    INSERT INTO public.system_audit_trail (timestamp, module, entity_type, entity_id, action, after_value, user_name, severity, payload_json)
    VALUES (now(),'BN_CONFIG','bn_screen_template',tpl_id::text,'SEED_CREATE',
      jsonb_build_object('template_code', tpl->>'code','template_name', tpl->>'name'),
      'SEED','info', jsonb_build_object('source','migration:seed-bn-screen-templates'));
  END LOOP;

  FOR asn IN SELECT * FROM jsonb_array_elements(assigns) LOOP
    UPDATE public.bn_product_version pv
    SET screen_template_id = (SELECT id FROM public.bn_screen_template WHERE template_code = asn->>'t'),
        modified_by = 'SEED', modified_at = now()
    FROM public.bn_product p
    WHERE pv.product_id = p.id
      AND p.country_code = 'SKN'
      AND p.benefit_code = asn->>'p'
      AND pv.status = 'ACTIVE'
      AND (pv.screen_template_id IS NULL OR pv.screen_template_id = 'a7e00001-7777-4000-b000-000000000001'::uuid);

    INSERT INTO public.system_audit_trail (timestamp, module, entity_type, entity_id, action, after_value, user_name, severity, payload_json)
    SELECT now(),'BN_CONFIG','bn_product_version', pv.id::text,'SCREEN_TEMPLATE_ASSIGNED',
      jsonb_build_object('benefit_code', p.benefit_code,'template_code', asn->>'t','screen_template_id', pv.screen_template_id),
      'SEED','info', jsonb_build_object('source','migration:seed-bn-screen-templates')
    FROM public.bn_product_version pv
    JOIN public.bn_product p ON p.id = pv.product_id
    WHERE p.country_code = 'SKN' AND p.benefit_code = asn->>'p' AND pv.status = 'ACTIVE' AND pv.modified_by = 'SEED';
  END LOOP;
END
$seed$;
